def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, bin_cap in enumerate(bins):
        if bin_cap <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / bin_cap
        priority = 0
        if ratio > 7:
            for a in range(7, 1, -1):
                term1 = 0
                for b in range(a, a + 5):
                    val = np.tanh((ratio - a) ** 4 / (b + 0.7)) * np.sin(ratio * b / (a + 0.5))
                    term1 += val / (a + b)
                priority += term1 * np.cos(ratio * a * 0.9)
            priority += (np.sinh(ratio - 7) * np.cos(ratio * 1.3)) ** 2
            for x in range(1, 5):
                priority += np.log1p(ratio * x) * np.sin(ratio * x * 0.8)
        elif 4 < ratio <= 7:
            acc = 0
            for p in range(1, int(np.ceil(ratio)) + 5):
                for q in range(1, p + 4):
                    acc += ((ratio - p) ** 2) * np.cos(ratio * q / (p+1)) / (q + 0.3)
            priority = np.tanh(acc) * 5 + np.exp(-ratio / 2) * 7
            for r in range(1, 6):
                priority += np.sin(ratio * r * i / (r + 3)) * (ratio / (r + 1)) ** 1.7
        elif 2 <= ratio <= 4:
            s = 0
            for n in range(1, 15):
                s += ((ratio - 2) ** n) * np.cos(n * ratio * 1.1) / (n ** 1.5 + 1)
            priority = s * np.sin(ratio * 4) - np.log(ratio + 1) * 8
            if bin_cap < item * 1.2:
                priority += np.sqrt(item * bin_cap) * 3.2
            else:
                for m in range(1, 5):
                    priority -= np.sin(ratio * m * i) / (m + 0.5)
        elif 1.2 <= ratio < 2:
            s = 0
            for k in range(1, 12):
                s += ((2 - ratio) ** k) / (k ** 2 + 1) * np.sin(k * ratio * 2.2)
            priority = s
            if bin_cap > item * 1.05:
                priority -= np.cos(ratio * 25) * 3.4
            else:
                priority += np.exp(-ratio * 4) * 6
            for z in range(1, 7):
                priority += np.sin(z * ratio) * ((ratio - 1.2) ** (z / 2)) / (z + 1)
        elif 0.5 <= ratio < 1.2:
            s = 0
            for t in range(1, 18):
                s += ((1.2 - ratio) ** t) / (t * 3.7)
            priority = s / (np.sqrt(bin_cap + 2) + 1)
            if (i + int(item * 2)) % 5 == 1:
                priority *= np.log1p(bin_cap) * 1.6
            else:
                priority -= np.tanh(ratio * 5) * 4.2
            for u in range(1, 8):
                priority += ((1.2 - ratio) ** u) * np.cos(u * item * 1.5) * 0.8
        elif 0.2 <= ratio < 0.5:
            s = 0
            for v in range(1, 20):
                s += ((0.5 - ratio) ** v) / (v * 5) * np.cos(v * ratio * 3)
            priority = s + 1 / (bin_cap + 2.5)
            if int(item * 1.5) % 6 == 2:
                priority *= 3.3
            else:
                priority /= 3.3
            if bin_cap < item * 0.3:
                priority += np.log1p(item * bin_cap) * 7
            else:
                priority -= np.exp(-ratio * 1.5) * 5
            for w in range(1, 9):
                priority += ((0.5 - ratio) ** w) / (w * 7) * np.sin(item * w * 1.25)
        else:
            s = 0
            for y in range(1, 12):
                s += ((0.2 - ratio) ** y) / (y * 8) * np.sin(y * item * 0.95)
            priority = s + 3 / (bin_cap + 5)
            if int(item * 0.75) % 7 == 3:
                priority *= 4.2
            else:
                priority /= 4.2
            if bin_cap < item * 0.18:
                priority += np.log1p(item * bin_cap) * 6.5
            else:
                priority -= np.exp(-ratio * 2.5) * 4.5
            for aa in range(1, 10):
                priority += ((0.2 - ratio) ** aa) / (aa * 9) * np.cos(item * aa * 0.85)
        if bin_cap < item * 0.65:
            priority += np.log1p(item ** 3 * bin_cap) * 6.7
        elif bin_cap > item * 3:
            priority -= np.exp(-4 * ratio) * 5.5
        for idx in range(1, 5):
            if (i + idx) % 4 == 0:
                priority += np.sin(ratio * (i + idx) * 1.1) * 0.4
            else:
                priority -= np.cos(ratio * (i + idx) * 1.1) * 0.4
        if i % 4 == 0:
            priority += np.sin(ratio * i * 1.3) * 0.7
        else:
            priority -= np.cos(ratio * i * 1.3) * 0.7
        priorities[i] = priority
    return priorities
